```typescript
import { useState } from 'react';
import { AIClient, AIError } from '@ipai/ai-sdk';

const client = new AIClient({
  supabaseUrl: process.env.NEXT_PUBLIC_SUPABASE_URL!,
  apiKey: process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
});

export function useAI() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const askQuestion = async (question: string) => {
    setLoading(true);
    setError(null);

    try {
      const result = await client.askQuestion({ question });
      return result;
    } catch (err) {
      if (err instanceof AIError) {
        setError(err.message);
      } else {
        setError('Unknown error occurred');
      }
      throw err;
    } finally {
      setLoading(false);
    }
  };

  return { askQuestion, loading, error };
}
```

## Architecture

### Edge Function Integration

```
Request → SDK Client
          ↓
          Supabase Edge Function (docs-ai-ask)
          ↓
          RAG Pipeline (Embeddings + Vector Search)
          ↓
          OpenAI GPT-4 (Answer Generation)
          ↓
          Response → SDK Client
```

### Fallback Strategy (Odoo Backend)

When Edge Function unavailable, Odoo backend falls back to direct OpenAI API:

```
Odoo → ai.client → Edge Function (primary)
                ↓ (if unavailable)
                OpenAI API (fallback)
```

SDK does NOT implement fallback (keeps client lightweight).

# InsightPulse AI Chat Widget & Design System

This package provides **two ways** to use the InsightPulse AI design system:

1. **React Component** - Full-featured chat widget for React applications
2. **Vanilla CSS Theme** - Pure CSS custom web theme for any website

Both implementations use the same Fluent 2-aligned design tokens for consistency.

---

## Option 1: React Component (for React apps)

### Installation

```bash
# In your React project
pnpm add @ipai/design-tokens
```

### Usage

```tsx
import { AIChatWidget, AIChatWidgetDemo } from '@ipai/design-tokens/react/AIChatWidget';

// Use the chat widget component
function App() {
  return (
    <div>
      <h1>My App</h1>
      <AIChatWidget />
    </div>
  );
}

// Or use the full demo page
function DemoPage() {
  return <AIChatWidgetDemo />;
}
```

