def check_expense_duplicates(
    odoo: OdooRpc,
    amount: float,
    date: Optional[str],
    name_hint: Optional[str],
) -> DupeResult:
    """
    Searches hr.expense for potential duplicates. Signals:
      - same total_amount within tolerance
      - same date
      - similar name (optional) is weaker and not used as hard constraint
    """
    hits: List[DupeHit] = []
    domain = []
    rows = odoo.call_kw(
        "hr.expense",
        "search_read",
        [domain],
        {
            "fields": ["id", "name", "date", "total_amount", "state"],
            "limit": 50,
            "order": "id desc",
        },
    )
    tol = max(2.0, 0.01 * max(amount, 1.0))
    for r in rows:
        amt = float(r.get("total_amount") or 0.0)
        if abs(amt - amount) <= tol:
            score = 0.5
            reason = "total_amount match within tolerance"
            if date and r.get("date") == date:
                score = 0.8
                reason = "total_amount+date match"
            hits.append(
                DupeHit(
                    model="hr.expense", record_id=int(r["id"]), score=score, reason=reason, fields=r
                )
            )

    risk = 0.0
    if hits:
        risk = _cap(max(h.score for h in hits))
    by_id = {}
    for h in hits:
        key = (h.model, h.record_id)
        if key not in by_id or h.score > by_id[key].score:
            by_id[key] = h
    return DupeResult(risk=risk, hits=list(by_id.values()))

from __future__ import annotations
import os
import json
import requests
from tenacity import retry, stop_after_attempt, wait_exponential


class LlmClient:
    def __init__(self):
        self.provider = os.getenv("LLM_PROVIDER", "openai").strip().lower()
        self.model = os.getenv("LLM_MODEL", "").strip()
        if not self.model:
            raise ValueError("LLM_MODEL is required")
        self.timeout = int(os.getenv("LLM_HTTP_TIMEOUT", "60"))

    @retry(stop=stop_after_attempt(3), wait=wait_exponential(min=1, max=8))
    def complete_json(self, prompt: str) -> dict:
        if self.provider == "openai":
            return self._openai(prompt)
        if self.provider == "anthropic":
            return self._anthropic(prompt)
        if self.provider == "gemini":
            return self._gemini(prompt)
        raise ValueError(f"Unsupported LLM_PROVIDER: {self.provider}")

    def generate(self, prompt: str, response_schema=None) -> dict:
        """Alias for complete_json with response_schema param (ignored)."""
        return self.complete_json(prompt)

    def _openai(self, prompt: str) -> dict:
        # Uses Chat Completions compatible endpoint.
        key = os.getenv("OPENAI_API_KEY")
        if not key:
            raise ValueError("OPENAI_API_KEY is required for openai provider")

        url = os.getenv("OPENAI_BASE_URL", "https://api.openai.com/v1/chat/completions")
        headers = {"Authorization": f"Bearer {key}", "Content-Type": "application/json"}

        payload = {
            "model": self.model,
            "messages": [{"role": "user", "content": prompt}],
            "temperature": 0,
            "response_format": {"type": "json_object"},
        }
        r = requests.post(url, headers=headers, data=json.dumps(payload), timeout=self.timeout)
        if r.status_code != 200:
            print(f"[LLM Error] Status {r.status_code}: {r.text[:500]}")
        r.raise_for_status()
        content = r.json()["choices"][0]["message"]["content"]
        return json.loads(content)

