REPO_ROOT = pathlib.Path(__file__).resolve().parents[3]
SSOT_DIR = REPO_ROOT / "platform" / "ssot"


def _find_yaml_files():
    """Collect all .yaml and .yml files under platform/ssot/."""
    files = []
    for ext in ("*.yaml", "*.yml"):
        files.extend(SSOT_DIR.rglob(ext))
    return sorted(files)


