            data = yaml.safe_load(f)
        if data is None:
            empties.append(str(filepath.relative_to(REPO_ROOT)))
    # Empty files are a warning, not a hard failure — but flag them
    if empties:
        pytest.skip(f"Empty YAML files (review needed): {empties}")

