version: 1
namespace: ops.leaderboard
last_reviewed: "2026-03-15"
description: >
  Data model for the IPAI Ops Console leaderboard page. Separates capability
  maturity scoring from release readiness, with provenance on every score and
  explicit links between blockers, remediation actions, and benchmark dimensions.

maturity_thresholds:
  - { min: 0,  max: 24,  label: missing }
  - { min: 25, max: 49,  label: scaffolded }
  - { min: 50, max: 74,  label: partial }
  - { min: 75, max: 89,  label: operational }
  - { min: 90, max: 100, label: hardened }

enums:
  maturity_label:
    values: [missing, scaffolded, partial, operational, hardened]
  blocker_severity:
    values: [critical, high, medium, low]
  action_status:
    values: [todo, in_progress, blocked, done]
  run_status:
    values: [running, completed, failed]

entities:
  evaluation_run:
    label: Evaluation Run
    description: Groups all scores from one evaluation pass into a single snapshot.
    primary_key: id
    fields:
      - { name: id, type: uuid, required: true }
      - { name: run_type, type: string, required: true }
      - { name: environment, type: string, required: true }
      - { name: commit_sha, type: string, required: false }
      - { name: source_mode, type: string, required: false }
      - { name: started_at, type: timestamptz, required: true }
      - { name: completed_at, type: timestamptz, required: false }
      - { name: status, type: enum, enum_ref: run_status, required: true }

{ name: run_type, type: string, required: true } - { name: environment, type: string, required: true } - { name: commit_sha, type: string, required: false } - { name: source_mode, type: string, required: false } - { name: started_at, type: timestamptz, required: true } - { name: completed_at, type: timestamptz, required: false } - { name: status, type: enum, enum_ref: run_status, required: true }

  maturity_domain_score:
    label: Domain Maturity Score
    description: One row per domain per evaluation run.
    primary_key: id
    fields:
      - { name: id, type: uuid, required: true }
      - { name: evaluation_run_id, type: uuid, required: true }
      - { name: domain_key, type: string, required: true }
      - { name: domain_label, type: string, required: true }
      - { name: score_pct, type: "numeric(5,2)", required: true }
      - { name: maturity_label, type: enum, enum_ref: maturity_label, required: true }
      - { name: passed_checks, type: integer, required: true }
      - { name: total_checks, type: integer, required: true }
      - { name: weight, type: "numeric(5,2)", required: false }
      - { name: trend_delta_pct, type: "numeric(5,2)", required: false }
      - { name: status, type: string, required: false }
      - { name: evidence_count, type: integer, required: false }
      - { name: blocker_count, type: integer, required: false }
      - { name: source_systems, type: jsonb, required: false }
      - { name: notes, type: string, required: false }
      - { name: evaluated_at, type: timestamptz, required: true }
      - { name: created_at, type: timestamptz, required: true }

} - { name: status, type: string, required: false } - { name: evidence_count, type: integer, required: false } - { name: blocker_count, type: integer, required: false } - { name: source_systems, type: jsonb, required: false } - { name: notes, type: string, required: false } - { name: evaluated_at, type: timestamptz, required: true } - { name: created_at, type: timestamptz, required: true }

  maturity_category_score:
    label: Category Maturity Score
    description: Rollup score for Microsoft Cloud chart categories.
    primary_key: id
