file_extension_policy:
  authoritative_docs: [".md"]
  authoritative_contracts: [".yaml", ".yml", ".json"]
  authoritative_diagrams: [".drawio"]  # exported as .png
  executable_truth: [".py", ".sh", ".ts", ".sql", ".tf", ".bicep"]
  extensions:
    ".md":       { purpose: "README, docs, ADRs, runbooks, specs", repos: "all" }
    ".yaml":     { purpose: "workflows, SSOT, contracts, CI, config", repos: "all" }
    ".yml":      { purpose: "alias for .yaml in CI tooling", repos: "all" }
    ".json":     { purpose: "manifests, machine-readable contracts", repos: "all" }
    ".jsonc":    { purpose: "local tooling config with comments", repos: ["agents", "platform", "design"] }
    ".py":       { purpose: "services, automation, eval runners, scripts", repos: ["odoo", "agents", "agent-platform", "automations", "data-intelligence"] }
    ".sh":       { purpose: "bootstrap, validation, release, ops wrappers", repos: "infra-heavy" }
    ".ts":       { purpose: "shared libraries, backend/frontend logic", repos: ["platform", "web", "design", "templates"] }
    ".tsx":      { purpose: "React UI apps and components", repos: ["web", "platform", "design"] }
    ".js":       { purpose: "build/tool scripts where TS not required", repos: ["web", ".github", "templates"] }
    ".sql":      { purpose: "migrations, analytics, validation queries", repos: ["platform", "data-intelligence", "odoo"] }
    ".tf":       { purpose: "Terraform IaC", repos: ["infra"] }
    ".bicep":    { purpose: "Azure-native declarative IaC", repos: ["infra"] }
    ".ipynb":    { purpose: "exploratory notebooks only, not authority", repos: ["data-intelligence", "agent-platform"] }
    ".toml":     { purpose: "Python/tooling config", repos: ["odoo", "agents", "agent-platform"] }
    ".conf":     { purpose: "runtime/app config", repos: ["odoo", "infra"] }
    ".xml":      { purpose: "Odoo views, data files, security", repos: ["odoo"] }
    ".po":       { purpose: "translation catalogs", repos: ["odoo"] }
    ".csv":      { purpose: "fixtures, reference mappings, test datasets", repos: ["odoo", "agents", "data-intelligence"] }
    ".parquet":  { purpose: "data artifacts for governed pipelines", repos: ["data-intelligence"] }
    ".svg":      { purpose: "logos, diagrams, icons", repos: ["design", "docs", "web"] }
    ".drawio":   { purpose: "canonical editable diagrams", repos: ["docs", "infra", "platform", "odoo"] }
    ".png":      { purpose: "exported previews, evidence, assets", repos: ["design", "docs", "web"] }
  banned:
    - ".env"     # never committed; use .env.example
    - ".pem"     # never committed; Key Vault only
    - ".key"     # never committed; Key Vault only

